class ViewController: UIViewController {
    override func viewDidLoad() {
        super.viewDidLoad()
        URLSession.shared.dataTask(with: URL(string: "https://api.app.com/dados")!) { data, _, _ in
            let dados = try! JSONDecoder().decode([Dado].self, from: data!)  // force unwrap + try!
            DispatchQueue.main.async {
                self.tableView.reloadData()  // sem separação de responsabilidade
            }
        }.resume()
    }
}

// Projeto de PLENO — sinais positivos:
@Observable
class DadosViewModel {
    var itens: [Dado] = []
    var erro: String?

    private let repositorio: DadoRepositorioProtocol

    init(repositorio: DadoRepositorioProtocol = DadoAPI()) {
        self.repositorio = repositorio  // injeção de dependência
    }

    func carregar() async {
        do {
            itens = try await repositorio.buscarTodos()
        } catch {
            self.erro = error.localizedDescription
        }
    }
}

